import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Aktualisieren von Fabric","description":"Eine Schritt-für-Schritt-Anleitung zum Aktualisieren von Fabric.","frontmatter":{"title":"Aktualisieren von Fabric","description":"Eine Schritt-für-Schritt-Anleitung zum Aktualisieren von Fabric.","authors":["IMB11","modmuss50"],"search":false,"files":[]},"headers":[],"relativePath":"de_de/1.20.4/players/updating-fabric.md","filePath":"versions/1.20.4/translated/de_de/players/updating-fabric.md","lastUpdated":1739538073000}`);var c={name:`de_de/1.20.4/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Aktualisieren von Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Aktualisieren von Fabric”">​</a></h1><p>Diese Anleitung wird das Aktualisieren von Fabric detailliert für den Minecraft-Launcher erklären.</p><p>Für die Launcher von Drittanbietern solltest du deren Dokumentation verwenden.</p><p>Das Vorgehen beim Aktualisieren von Fabric ist der Installation ähnlich, deshalb werden sich Teile dieser Anleitung mit der Anleitung <a href="./installing-fabric">Installation von Fabric</a> überschneiden.</p><h2 id="warum-sollte-ich-den-fabric-loader-aktualisieren" tabindex="-1">Warum sollte ich den Fabric-Loader aktualisieren? <a class="header-anchor" href="#warum-sollte-ich-den-fabric-loader-aktualisieren" aria-label="Permalink to “Warum sollte ich den Fabric-Loader aktualisieren?”">​</a></h2><p>Neuere Mods können eine neuere Version des Fabric-Loaders benötigen, um zu funktionieren, weshalb es wichtig ist, ihn auf dem neuesten Stand zu halten, um immer die neuesten Mods benutzen zu können.</p><p>Für die Launcher von Drittanbietern solltest du deren Dokumentation verwenden.</p><h2 id="_1-herunterladen-des-fabric-installers" tabindex="-1">1. Herunterladen des Fabric-Installers <a class="header-anchor" href="#_1-herunterladen-des-fabric-installers" aria-label="Permalink to “1. Herunterladen des Fabric-Installers”">​</a></h2><p>Der Fabric-Installer kann von der <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric-Webseite</a> heruntergeladen werden.</p><p>Wenn du Windows verwendest, lade die <code>.exe</code>-Version (<code>Download For Windows</code>) herunter, da sie keine Java-Installation auf dem System benötigt. Stattdessen wird die Java-Installation des offiziellen Launchers verwendet.</p><p>Für macOS und Linux solltest du die <code>.jar</code>-Version verwenden. Manchmal musst du Java vor diesem Schritt installieren.</p><h2 id="_2-ausfuhren-des-fabric-installers" tabindex="-1">2. Ausführen des Fabric-Installers <a class="header-anchor" href="#_2-ausfuhren-des-fabric-installers" aria-label="Permalink to “2. Ausführen des Fabric-Installers”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Schließe zuerst Minecraft und den Minecraft-Launcher vor Beginn der Installation.</p></div><details class="details custom-block"><summary>Informationen für macOS-Nutzer</summary><p>Auf macOS musst du möglicherweise zuerst einen Rechtsklick auf die <code>.jar</code>-Datei im Downloads-Verzeichnis machen, und <code>Öffnen</code> zum Ausführen klicken.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="MacOS Kontextmenü im Fabric-Installer" loading="lazy"></p><p>Bei der Frage &quot;Möchten Sie es wirklich öffnen?&quot;, klicke erneut auf <code>Öffnen</code>.</p></details><p>Wenn du den Installer geöffnet hast, sollte diese Oberfläche erscheinen:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric-Installer mit &quot;Installieren&quot; hervorgehoben" loading="lazy"></p><p>Um Fabric zu installieren, wähle einfach die Spielversion aus der Liste und klicke installieren.</p><p>Um Fabric zu aktualisieren, stelle sicher, dass die Spielversion und die Loader-Version korrekt sind und klicke auf <code>Installieren</code>.</p><p><strong>Stelle sicherm dass die Option &#39;Profil erstellen&#39;&#39; deaktiviert ist, wenn du den Installer ausführst, da sonst ein neues Profil erstellt wird, das in diesem Fall nicht benötigt wird.</strong></p><h2 id="_3-offne-das-profil-im-minecraft-launcher" tabindex="-1">3. Öffne das Profil im Minecraft-Launcher <a class="header-anchor" href="#_3-offne-das-profil-im-minecraft-launcher" aria-label="Permalink to “3. Öffne das Profil im Minecraft-Launcher”">​</a></h2><p>Sobald die Installation beendet ist, kannst du den Minecraft-Launcher öffnen und zum <code>Installationen</code>-Tab navigieren. Wähle dein Fabric-Profil und öffne die Bearbeitungsoberfläche.</p><p>Ersetze die Version mit der neuen Version des Fabric-Loaders, die gerade installiert wurde und klicke auf <code>Speichern</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Aktualisieren der Fabric-Loader-Version im Minecraft-Launcher" loading="lazy"></p><h2 id="_4-du-hast-es-geschafft" tabindex="-1">4. Du hast es geschafft! <a class="header-anchor" href="#_4-du-hast-es-geschafft" aria-label="Permalink to “4. Du hast es geschafft!”">​</a></h2><p>Wenn du mit allen Schritten fertig bist, kannst du zurück zum <code>Spielen</code>-Tab navigieren, das Fabric-Profil aus der Liste in der unteren linken Ecke auswählen und spielen!</p><p>Fall dir beim Folgen dieser Anleitungen irgendwelche Fehler auftreten, kannst du nach Hilfe im <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric-Discord</a> im Kanal <code>#player-support</code> fragen.</p>`,26)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};